+import Yoga from 'yoga-layout';
+import {type DOMElement, type DOMNode} from './dom.js';
+import applyStyles from './styles.js';
+
+type Track =
+	| {type: 'fixed'; size: number}
+	| {type: 'fr'; fraction: number; min: number}
+	| {type: 'auto'};
+
+type Placement = {start: number; end: number};
+
+const tokenizeTracks = (template: string): string[] => {
+	const tracks: string[] = [];
+	let current = '';
+	let depth = 0;
+
+	for (const character of template.trim()) {
+		if (character === '(') depth++;
+		if (character === ')') depth--;
+		if (/\\s/.test(character) && depth === 0) {
+			if (current) tracks.push(current);
+			current = '';
+		} else {
+			current += character;
+		}
+	}
+
+	if (current) tracks.push(current);
+	return tracks;
+};
+
+const parseTrack = (value: string): Track => {
+	if (value === 'auto') return {type: 'auto'};
+	const fixed = Number(value);
+	if (Number.isFinite(fixed) && fixed >= 0) return {type: 'fixed', size: fixed};
+	const fr = /^(\\d*\\.?\\d+)fr$/.exec(value);
+	if (fr) return {type: 'fr', fraction: Number(fr[1]), min: 0};
+	const minmax = /^minmax\\(\\s*(\\d*\\.?\\d+)\\s*,\\s*(\\d*\\.?\\d+|\\d*\\.?\\d+fr)\\s*\\)$/.exec(value);
+	if (minmax) {
+		const min = Number(minmax[1]);
+		if (minmax[2].endsWith('fr')) {
+			return {type: 'fr', fraction: Number.parseFloat(minmax[2]), min};
+		}
+
+		return {type: 'fixed', size: Number(minmax[2])};
+	}
+
+	throw new Error(`Invalid grid track size: ${value}`);
+};
+
+const parseTracks = (template: string | undefined): Track[] =>
+	template ? tokenizeTracks(template).map(parseTrack) : [];
+
+const parsePlacement = (value: number | string | undefined): Placement | undefined => {
+	if (typeof value === 'number') return {start: value - 1, end: value};
+	if (!value) return undefined;
+	const match = /^(\\d+)\\s*\\/\\s*(\\d+)$/.exec(value);
+	if (match) return {start: Number(match[1]) - 1, end: Number(match[2]) - 1};
+	const index = Number(value);
+	if (Number.isInteger(index)) return {start: index - 1, end: index};
+	throw new Error(`Invalid grid placement: ${value}`);
+};
+
+const resolveTracks = (tracks: Track[], available: number, autoSizes: number[]): number[] => {
+	const minimum = tracks.reduce((total, track, index) => total +
+		(track.type === 'fixed' ? track.size : track.type === 'fr' ? track.min : autoSizes[index] ?? 0), 0);
+	const fractionTotal = tracks.reduce((total, track) => total + (track.type === 'fr' ? track.fraction : 0), 0);
+	const remaining = Math.max(0, available - minimum);
+	return tracks.map((track, index) => {
+		if (track.type === 'fixed') return track.size;
+		if (track.type === 'auto') return autoSizes[index] ?? 0;
+		return track.min + (fractionTotal > 0 ? remaining * track.fraction / fractionTotal : 0);
+	});
+};
+
+const sumRange = (tracks: number[], start: number, end: number, gap: number): number =>
+	tracks.slice(start, end).reduce((total, size) => total + size, 0) + Math.max(0, end - start - 1) * gap;
+
+const offsetOf = (tracks: number[], index: number, gap: number): number =>
+	sumRange(tracks, 0, index, gap) + (index > 0 ? gap : 0);
